def compute_wql(true, pred, quantiles=[0.1, 0.5, 0.9]):
    """Compute Weighted Quantile Loss (WQL)"""
    total_loss = 0
    for q in quantiles:
        errors = true - pred
        total_loss += np.mean(np.maximum(q * errors, (q - 1) * errors))
    return total_loss / len(quantiles)
